    "lib/spark-alm-controller/deploy/ForeignControllerInit.sol": {
      "content": "// SPDX-License-Identifier: AGPL-3.0-or-later
pragma solidity >=0.8.0;

import { ForeignController } from "../src/ForeignController.sol";

import { IALMProxy }   from "../src/interfaces/IALMProxy.sol";
import { IRateLimits } from "../src/interfaces/IRateLimits.sol";

import { ControllerInstance } from "./ControllerInstance.sol";

interface IPSM3Like {
    function susds() external view returns (address);
    function totalAssets() external view returns (uint256);
    function totalShares() external view returns (uint256);
    function usdc() external view returns (address);
    function usds() external view returns (address);
}

library ForeignControllerInit {

    /**********************************************************************************************/
    /*** Structs and constants                                                                  ***/
    /**********************************************************************************************/

    struct CheckAddressParams {
        address admin;
        address psm;
        address cctp;
        address usdc;
        address susds;
        address usds;
    }

    struct ConfigAddressParams {
        address   freezer;
        address[] relayers;
        address   oldController;
    }

    struct MintRecipient {
        uint32  domain;
        bytes32 mintRecipient;
    }

    struct LayerZeroRecipient {
        uint32  destinationEndpointId;
        bytes32 recipient;
    }

    struct MaxSlippageParams {
        address pool;
        uint256 maxSlippage;
    }

    bytes32 constant DEFAULT_ADMIN_ROLE = 0x00;

    /**********************************************************************************************/
    /*** Internal library functions                                                             ***/
    /**********************************************************************************************/

    function initAlmSystem(
        ControllerInstance   memory controllerInst,
        ConfigAddressParams  memory configAddresses,
        CheckAddressParams   memory checkAddresses,
        MintRecipient[]      memory mintRecipients,
        LayerZeroRecipient[] memory layerZeroRecipients,
        MaxSlippageParams[]  memory maxSlippageParams,
        bool                 checkPsm
    )
        internal
    {
        // Step 1: Do sanity checks outside of the controller

        require(IALMProxy(controllerInst.almProxy).hasRole(DEFAULT_ADMIN_ROLE, checkAddresses.admin),     "ForeignControllerInit/incorrect-admin-almProxy");
        require(IRateLimits(controllerInst.rateLimits).hasRole(DEFAULT_ADMIN_ROLE, checkAddresses.admin), "ForeignControllerInit/incorrect-admin-rateLimits");

        // Step 2: Initialize the controller

        _initController(controllerInst, configAddresses, checkAddresses, mintRecipients, layerZeroRecipients, maxSlippageParams, checkPsm);
    }

    function upgradeController(
        ControllerInstance   memory controllerInst,
        ConfigAddressParams  memory configAddresses,
        CheckAddressParams   memory checkAddresses,
        MintRecipient[]      memory mintRecipients,
        LayerZeroRecipient[] memory layerZeroRecipients,
        MaxSlippageParams[]  memory maxSlippageParams,
        bool                 checkPsm
    )
        internal
    {
        _initController(controllerInst, configAddresses, checkAddresses, mintRecipients, layerZeroRecipients, maxSlippageParams, checkPsm);

        IALMProxy   almProxy   = IALMProxy(controllerInst.almProxy);
        IRateLimits rateLimits = IRateLimits(controllerInst.rateLimits);

        require(configAddresses.oldController != address(0), "ForeignControllerInit/old-controller-zero-address");

        require(almProxy.hasRole(almProxy.CONTROLLER(), configAddresses.oldController),     "ForeignControllerInit/old-controller-not-almProxy-controller");
        require(rateLimits.hasRole(rateLimits.CONTROLLER(), configAddresses.oldController), "ForeignControllerInit/old-controller-not-rateLimits-controller");

        almProxy.revokeRole(almProxy.CONTROLLER(), configAddresses.oldController);
        rateLimits.revokeRole(rateLimits.CONTROLLER(), configAddresses.oldController);
    }

    /**********************************************************************************************/
    /*** Private helper functions                                                               ***/
    /**********************************************************************************************/

    function _initController(
        ControllerInstance   memory controllerInst,
        ConfigAddressParams  memory configAddresses,
        CheckAddressParams   memory checkAddresses,
        MintRecipient[]      memory mintRecipients,
        LayerZeroRecipient[] memory layerZeroRecipients,
        MaxSlippageParams[]  memory maxSlippageParams,
        bool                 checkPsm
    )
        private
    {
        // Step 1: Perform controller sanity checks

        ForeignController newController = ForeignController(controllerInst.controller);

        require(newController.hasRole(DEFAULT_ADMIN_ROLE, checkAddresses.admin), "ForeignControllerInit/incorrect-admin-controller");

        require(address(newController.proxy())      == controllerInst.almProxy,   "ForeignControllerInit/incorrect-almProxy");
        require(address(newController.rateLimits()) == controllerInst.rateLimits, "ForeignControllerInit/incorrect-rateLimits");

        require(address(newController.psm())  == checkAddresses.psm,  "ForeignControllerInit/incorrect-psm");
        require(address(newController.usdc()) == checkAddresses.usdc, "ForeignControllerInit/incorrect-usdc");
        require(address(newController.cctp()) == checkAddresses.cctp, "ForeignControllerInit/incorrect-cctp");

        require(configAddresses.oldController != address(newController), "ForeignControllerInit/old-controller-is-new-controller");

        // Step 2: Perform PSM sanity checks

        if (checkPsm) {
            IPSM3Like psm = IPSM3Like(checkAddresses.psm);

            require(psm.totalAssets() >= 1e18, "ForeignControllerInit/psm-totalAssets-not-seeded");
            require(psm.totalShares() >= 1e18, "ForeignControllerInit/psm-totalShares-not-seeded");

            require(psm.usdc()  == checkAddresses.usdc,  "ForeignControllerInit/psm-incorrect-usdc");
            require(psm.usds()  == checkAddresses.usds,  "ForeignControllerInit/psm-incorrect-usds");
            require(psm.susds() == checkAddresses.susds, "ForeignControllerInit/psm-incorrect-susds");
        }

        // Step 3: Configure ACL permissions controller, almProxy, and rateLimits

        IALMProxy   almProxy   = IALMProxy(controllerInst.almProxy);
        IRateLimits rateLimits = IRateLimits(controllerInst.rateLimits);

        almProxy.grantRole(almProxy.CONTROLLER(),        address(newController));
        newController.grantRole(newController.FREEZER(), configAddresses.freezer);
        rateLimits.grantRole(rateLimits.CONTROLLER(),    address(newController));

        for (uint256 i; i < configAddresses.relayers.length; ++i) {
            newController.grantRole(newController.RELAYER(), configAddresses.relayers[i]);
        }

        // Step 4: Configure the mint recipients on other domains

        for (uint256 i; i < mintRecipients.length; ++i) {
            newController.setMintRecipient(mintRecipients[i].domain, mintRecipients[i].mintRecipient);
        }

        // Step 5: Configure LayerZero recipients

        for (uint256 i; i < layerZeroRecipients.length; ++i) {
            newController.setLayerZeroRecipient(layerZeroRecipients[i].destinationEndpointId, layerZeroRecipients[i].recipient);
        }

        // Step 6: Configure max slippage

        for (uint256 i; i < maxSlippageParams.length; ++i) {
            newController.setMaxSlippage(maxSlippageParams[i].pool, maxSlippageParams[i].maxSlippage);
        }
    }

}
"
    },
    "src/libraries/SLLHelpers.sol": {
      "content": "// SPDX-License-Identifier: AGPL-3.0

pragma solidity ^0.8.0;

import { IAToken } from "aave-v3-origin/src/core/contracts/interfaces/IAToken.sol";

import { IERC4626 } from "forge-std/interfaces/IERC4626.sol";

import { IMetaMorpho } from "metamorpho/interfaces/IMetaMorpho.sol";

import { MarketParams, Id } from "morpho-blue/src/interfaces/IMorpho.sol";
import { MarketParamsLib }  from "morpho-blue/src/libraries/MarketParamsLib.sol";

import { SafeERC20, IERC20 } from "openzeppelin-contracts/contracts/token/ERC20/utils/SafeERC20.sol";
import { IERC20Metadata }    from "openzeppelin-contracts/contracts/token/ERC20/extensions/IERC20Metadata.sol";

import { Arbitrum }  from "spark-address-registry/Arbitrum.sol";
import { Avalanche } from "spark-address-registry/Avalanche.sol";
import { Base }      from "spark-address-registry/Base.sol";
import { Ethereum }  from "spark-address-registry/Ethereum.sol";
import { Optimism }  from "spark-address-registry/Optimism.sol";
import { Unichain }  from "spark-address-registry/Unichain.sol";

import { ControllerInstance }    from "spark-alm-controller/deploy/ControllerInstance.sol";
import { MainnetControllerInit } from "spark-alm-controller/deploy/MainnetControllerInit.sol";
import { ForeignControllerInit } from "spark-alm-controller/deploy/ForeignControllerInit.sol";
import { IRateLimits }           from "spark-alm-controller/src/interfaces/IRateLimits.sol";
import { MainnetController }     from "spark-alm-controller/src/MainnetController.sol";
import { RateLimitHelpers }      from "spark-alm-controller/src/RateLimitHelpers.sol";

import { CCTPForwarder } from "xchain-helpers/forwarders/CCTPForwarder.sol";

import { ISparkVaultV2Like } from "src/interfaces/Interfaces.sol";

/**
 * @notice Helper functions for Spark Liquidity Layer
 */
library SLLHelpers {

    struct RateLimitData {
        uint256 maxAmount;
        uint256 slope;
    }

    // This is the same on all chains
    address internal constant MORPHO = 0xBBBBBbbBBb9cC5e90e3b3Af64bdAF62C37EEFFCb;

    bytes32 internal constant LIMIT_4626_DEPOSIT   = keccak256("LIMIT_4626_DEPOSIT");
    bytes32 internal constant LIMIT_4626_WITHDRAW  = keccak256("LIMIT_4626_WITHDRAW");
    bytes32 internal constant LIMIT_AAVE_DEPOSIT   = keccak256("LIMIT_AAVE_DEPOSIT");
    bytes32 internal constant LIMIT_AAVE_WITHDRAW  = keccak256("LIMIT_AAVE_WITHDRAW");
    bytes32 internal constant LIMIT_USDS_MINT      = keccak256("LIMIT_USDS_MINT");
    bytes32 internal constant LIMIT_USDS_TO_USDC   = keccak256("LIMIT_USDS_TO_USDC");
    bytes32 internal constant LIMIT_USDC_TO_CCTP   = keccak256("LIMIT_USDC_TO_CCTP");
    bytes32 internal constant LIMIT_USDC_TO_DOMAIN = keccak256("LIMIT_USDC_TO_DOMAIN");
    bytes32 internal constant LIMIT_PSM_DEPOSIT    = keccak256("LIMIT_PSM_DEPOSIT");
    bytes32 internal constant LIMIT_PSM_WITHDRAW   = keccak256("LIMIT_PSM_WITHDRAW");
    bytes32 internal constant LIMIT_CURVE_DEPOSIT  = keccak256("LIMIT_CURVE_DEPOSIT");
    bytes32 internal constant LIMIT_CURVE_SWAP     = keccak256("LIMIT_CURVE_SWAP");
    bytes32 internal constant LIMIT_CURVE_WITHDRAW = keccak256("LIMIT_CURVE_WITHDRAW");

    /**
     * @notice Activate the bare minimum for Spark Liquidity Layer
     * @dev Sets PSM and CCTP rate limits.
     */
    function activateSparkLiquidityLayer(
        address rateLimits,
        address usdc,
        address usds,
        address susds,
        RateLimitData memory usdcDeposit,
        RateLimitData memory usdcWithdraw,
        RateLimitData memory cctpEthereumDeposit
    ) internal {
        // PSM USDC
        setRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_PSM_DEPOSIT,
                usdc
            ),
            rateLimits,
            usdcDeposit.maxAmount,
            usdcDeposit.slope,
            6
        );

        setRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_PSM_WITHDRAW,
                usdc
            ),
            rateLimits,
            usdcWithdraw.maxAmount,
            usdcWithdraw.slope,
            6
        );

        // PSM USDS
        IRateLimits(rateLimits).setUnlimitedRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_PSM_DEPOSIT,
                usds
            )
        );

        IRateLimits(rateLimits).setUnlimitedRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_PSM_WITHDRAW,
                usds
            )
        );

        // PSM sUSDS
        IRateLimits(rateLimits).setUnlimitedRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_PSM_DEPOSIT,
                susds
            )
        );

        IRateLimits(rateLimits).setUnlimitedRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_PSM_WITHDRAW,
                susds
            )
        );

        // CCTP
        IRateLimits(rateLimits).setUnlimitedRateLimitData(
            LIMIT_USDC_TO_CCTP
        );

        setRateLimitData(
            RateLimitHelpers.makeUint32Key(
                LIMIT_USDC_TO_DOMAIN,
                0  // Ethereum domain id (https://developers.circle.com/stablecoins/evm-smart-contracts)
            ),
            rateLimits,
            cctpEthereumDeposit.maxAmount,
            cctpEthereumDeposit.slope,
            6
        );
    }

    /**
     * @notice Configure an Aave token
     * @dev This will set the deposit to the given numbers with
     *      the withdraw limit set to unlimited.
     */
    function configureAaveToken(
        address rateLimits,
        address token,
        uint256 depositMax,
        uint256 depositSlope
    ) internal {
        IERC20 underlying = IERC20(IAToken(token).UNDERLYING_ASSET_ADDRESS());

        setRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_AAVE_DEPOSIT,
                token
            ),
            rateLimits,
            depositMax,
            depositSlope,
            IERC20Metadata(address(underlying)).decimals()
        );

        IRateLimits(rateLimits).setUnlimitedRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_AAVE_WITHDRAW,
                token
            )
        );
    }

    /**
     * @notice Configure an ERC4626 vault
     * @dev This will set the deposit to the given numbers with
     *      the withdraw limit set to unlimited.
     */
    function configureERC4626Vault(
        address controller,
        address rateLimits,
        address vault,
        uint256 depositMax,
        uint256 depositSlope,
        uint256 maxExchangeRate
    ) internal {
        address asset = IERC4626(vault).asset();

        configureERC4626Vault(rateLimits, vault, depositMax, depositSlope, type(uint256).max, 0);

        MainnetController(controller).setMaxExchangeRate(
            vault,
            1 * 10 ** IERC20Metadata(vault).decimals(),
            maxExchangeRate * 10 ** IERC20Metadata(asset).decimals()
        );
    }

    /**
     * @notice Configure an ERC4626 vault rate limits
     */
    function configureERC4626Vault(
        address rateLimits,
        address vault,
        uint256 depositMax,
        uint256 depositSlope,
        uint256 withdrawMax,
        uint256 withdrawSlope
    ) internal {
        IERC20 asset = IERC20(IERC4626(vault).asset());

        setRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_4626_DEPOSIT,
                vault
            ),
            rateLimits,
            depositMax,
            depositSlope,
            IERC20Metadata(address(asset)).decimals()
        );

        setRateLimitData(
            RateLimitHelpers.makeAddressKey(
                LIMIT_4626_WITHDRAW,
                vault
            ),
            rateLimits,
            withdrawMax,
            withdrawSlope,
            IERC20Metadata(address(asset)).decimals()
        );
    }

    function onboardERC4626Vault(
        address controller,
        address rateLimits,
        address vault,
        uint256 depositMax,
        uint256 depositSlope
    )
        internal
    {
        address asset = IERC4626(vault).asset();

        configureERC4626Vault(rateLimits, vault, depositMax, depositSlope, type(uint256).max, 0);

        MainnetController(controller).setMaxExchangeRate(
            vault,
            1 * 10 ** IERC20Metadata(vault).decimals(),
            10 * 10 ** IERC20Metadata(address(asset)).decimals()
        );
    }

    function onboardERC4626Vault(
        address controller,
        address rateLimits,
        address vault,
        uint256 depositMax,
        uint256 depositSlope,
        uint256 withdrawMax,
        uint256 withdrawSlope
    )
        internal
    {
        address asset = IERC4626(vault).asset();

        configureERC4626Vault(
            rateLimits,
            vault,
            depositMax,
            depositSlope,
            withdrawMax,
            withdrawSlope
        );

        MainnetController(controller).setMaxExchangeRate(
            vault,
            1 * 10 ** IERC20Metadata(vault).decimals(),
            10 * 10 ** IERC20Metadata(address(asset)).decimals()
        );
    }

    function setMaxExchangeRate(
        address almController,
        address vault, 
        uint256 normalizedShares, 
        uint256 normalizedAssets
    ) 
        internal 
    {
        uint256 sharePrecision = 10 ** IERC20Metadata(vault).decimals();
        uint256 assetPrecision = 10 ** IERC20Metadata(IERC4626(vault).asset()).decimals();

        MainnetController(almController).setMaxExchangeRate({
            token             : vault,
            shares            : normalizedShares * sharePrecision,
            maxExpectedAssets : normalizedAssets * assetPrecision
        });
    }

    /**
     * @notice Onboard a Curve pool
     */
    function configureCurvePool(
        address controller,
        address rateLimits,
        address pool,
        uint256 maxSlippage,
        uint256 swapMax,
        uint256 swapSlope,
        uint256 depositMax,
        uint256 depositSlope,
        uint256 withdrawMax,
        uint256 withdrawSlope
    ) internal {
        MainnetController(controller).setMaxSlippage(pool, maxSlippage);

        if (swapMax != 0) {
            setRateLimitData(
                RateLimitHelpers.makeAddressKey(
                    LIMIT_CURVE_SWAP,
                    pool
                ),
                rateLimits,
                swapMax,
                swapSlope,
                18
            );
        }

        if (depositMax != 0) {
            setRateLimitData(
                RateLimitHelpers.makeAddressKey(
                    LIMIT_CURVE_DEPOSIT,
                    pool
                ),
                rateLimits,
                depositMax,
                depositSlope,
                18
            );
        }

        if (withdrawMax != 0) {
            setRateLimitData(
                RateLimitHelpers.makeAddressKey(
                    LIMIT_CURVE_WITHDRAW,
                    pool
                ),
                rateLimits,
                withdrawMax,
                withdrawSlope,
                18
            );
        }
    }

    function configureUniswapV4Pool(
        address controller,
        address rateLimits,
        bytes32 poolId,
        uint256 maxSlippage,
        int24   tickLower,
        int24   tickUpper,
        uint24  maxTickSpacing,
        uint256 depositMax,
        uint256 depositSlope,
        uint256 withdrawMax,
        uint256 withdrawSlope,
        uint256 swapMax,
        uint256 swapSlope
    ) internal {
        MainnetController(controller).setUniswapV4TickLimits(poolId, tickLower, tickUpper, maxTickSpacing);
        MainnetController(controller).setMaxSlippage(address(uint160(uint256(poolId))), maxSlippage);

        if (depositMax != 0) {
            setRateLimitData(
                RateLimitHelpers.makeBytes32Key(
                    MainnetController(controller).LIMIT_UNISWAP_V4_DEPOSIT(),
                    poolId
                ),
                rateLimits,
                depositMax,
                depositSlope,
                18
            );
        }

        if (withdrawMax != 0) {
            setRateLimitData(
                RateLimitHelpers.makeBytes32Key(
                    MainnetController(controller).LIMIT_UNISWAP_V4_WITHDRAW(),
                    poolId
                ),
                rateLimits,
                withdrawMax,
                withdrawSlope,
                18
            );
        }

        if (swapMax != 0) {
            setRateLimitData(
                RateLimitHelpers.makeBytes32Key(
                    MainnetController(controller).LIMIT_UNISWAP_V4_SWAP(),
                    poolId
                ),
                rateLimits,
                swapMax,
                swapSlope,
                18
            );
        }
    }

    function morphoIdleMarket(
        address asset
    ) internal pure returns (MarketParams memory) {
        return MarketParams({
            loanToken:       asset,
            collateralToken: address(0),
            oracle:          address(0),
            irm:             address(0),
            lltv:            0
        });
    }

    /**
     * @notice Activate a Morpho Vault
     * @dev This will do the following:
     *      - Add the relayer as an allocator
     *      - Add the idle market for the underlying asset with unlimited size
     *      - Set the supply queue to the idle market
     */
    function activateMorphoVault(
        address vault,
        address relayer
    ) internal {
        IERC20 asset = IERC20(IERC4626(vault).asset());
        MarketParams memory idleMarket = morphoIdleMarket(address(asset));

        IMetaMorpho(vault).setIsAllocator(
            relayer,
            true
        );

        IMetaMorpho(vault).submitCap(
            idleMarket,
            type(uint184).max
        );

        IMetaMorpho(vault).acceptCap(
            idleMarket
        );

        Id[] memory supplyQueue = new Id[](1);
        supplyQueue[0] = MarketParamsLib.id(idleMarket);
        IMetaMorpho(vault).setSupplyQueue(supplyQueue);
    }

    function setUSDSMintRateLimit(
        address rateLimits,
        uint256 maxAmount,
        uint256 slope
    ) internal {
        setRateLimitData(
            LIMIT_USDS_MINT,
            rateLimits,
            maxAmount,
            slope,
            18
        );
    }

    function setUSDSToUSDCRateLimit(
        address rateLimits,
        uint256 maxUsdcAmount,
        uint256 slope
    ) internal {
        setRateLimitData(
            LIMIT_USDS_TO_USDC,
            rateLimits,
            maxUsdcAmount,
            slope,
            6
        );
    }

    function setUSDCToCCTPRateLimit(
        address rateLimits,
        uint256 maxUsdcAmount,
        uint256 slope
    ) internal {
        setRateLimitData(
            LIMIT_USDC_TO_CCTP,
            rateLimits,
            maxUsdcAmount,
            slope,
            6
        );
    }

    function setUSDCToDomainRateLimit(
        address rateLimits,
        uint32  destinationDomain,
        uint256 maxUsdcAmount,
        uint256 slope
    ) internal {
        setRateLimitData(
            RateLimitHelpers.makeUint32Key(LIMIT_USDC_TO_DOMAIN, destinationDomain),
            rateLimits,
            maxUsdcAmount,
            slope,
            6
        );
    }

    function addrToBytes32(address addr) internal pure returns (bytes32) {
        return bytes32(uint256(uint160(addr)));
    }

    function upgradeMainnetController(address oldController, address newController) internal {
        MainnetControllerInit.MintRecipient[] memory mintRecipients = new MainnetControllerInit.MintRecipient[](5);

        mintRecipients[0] = MainnetControllerInit.MintRecipient({
            domain        : CCTPForwarder.DOMAIN_ID_CIRCLE_BASE,
            mintRecipient : addrToBytes32(Base.ALM_PROXY)
        });

        mintRecipients[1] = MainnetControllerInit.MintRecipient({
            domain        : CCTPForwarder.DOMAIN_ID_CIRCLE_ARBITRUM_ONE,
            mintRecipient : addrToBytes32(Arbitrum.ALM_PROXY)
        });

        mintRecipients[2] = MainnetControllerInit.MintRecipient({
            domain        : CCTPForwarder.DOMAIN_ID_CIRCLE_OPTIMISM,
            mintRecipient : addrToBytes32(Optimism.ALM_PROXY)
        });

        mintRecipients[3] = MainnetControllerInit.MintRecipient({
            domain        : CCTPForwarder.DOMAIN_ID_CIRCLE_UNICHAIN,
            mintRecipient : addrToBytes32(Unichain.ALM_PROXY)
        });

        mintRecipients[4] = MainnetControllerInit.MintRecipient({
            domain        : CCTPForwarder.DOMAIN_ID_CIRCLE_AVALANCHE,
            mintRecipient : addrToBytes32(Avalanche.ALM_PROXY)
        });

        MainnetControllerInit.LayerZeroRecipient[] memory layerZeroRecipients = new MainnetControllerInit.LayerZeroRecipient[](0);

        MainnetControllerInit.MaxSlippageParams[] memory maxSlippageParams = new MainnetControllerInit.MaxSlippageParams[](0);

        address[] memory relayers = new address[](2);
        relayers[0] = Ethereum.ALM_RELAYER_MULTISIG;
        relayers[1] = Ethereum.ALM_BACKSTOP_RELAYER_MULTISIG;

        MainnetControllerInit.upgradeController({
            controllerInst: ControllerInstance({
                almProxy   : Ethereum.ALM_PROXY,
                controller : newController,
                rateLimits : Ethereum.ALM_RATE_LIMITS
            }),
            configAddresses: MainnetControllerInit.ConfigAddressParams({
                freezer       : Ethereum.ALM_FREEZER_MULTISIG,
                relayers      : relayers,
                oldController : oldController
            }),
            checkAddresses: MainnetControllerInit.CheckAddressParams({
                admin      : Ethereum.SPARK_PROXY,
                proxy      : Ethereum.ALM_PROXY,
                rateLimits : Ethereum.ALM_RATE_LIMITS,
                vault      : Ethereum.ALLOCATOR_VAULT,
                psm        : Ethereum.PSM,
                daiUsds    : Ethereum.DAI_USDS,
                cctp       : Ethereum.CCTP_TOKEN_MESSENGER
            }),
            mintRecipients:      mintRecipients,
            layerZeroRecipients: layerZeroRecipients,
            maxSlippageParams:   maxSlippageParams
        });
    }

    function upgradeForeignController(
        ControllerInstance memory controllerInst,
        ForeignControllerInit.ConfigAddressParams memory configAddresses,
        ForeignControllerInit.CheckAddressParams memory checkAddresses,
        bool checkPsm
    ) internal {
        ForeignControllerInit.MintRecipient[] memory mintRecipients = new ForeignControllerInit.MintRecipient[](1);

        mintRecipients[0] = ForeignControllerInit.MintRecipient({
            domain        : CCTPForwarder.DOMAIN_ID_CIRCLE_ETHEREUM,
            mintRecipient : addrToBytes32(Ethereum.ALM_PROXY)
        });

        ForeignControllerInit.LayerZeroRecipient[] memory layerZeroRecipients = new ForeignControllerInit.LayerZeroRecipient[](0);

        ForeignControllerInit.MaxSlippageParams[] memory maxSlippageParams = new ForeignControllerInit.MaxSlippageParams[](0);

        ForeignControllerInit.upgradeController({
            controllerInst:      controllerInst,
            configAddresses:     configAddresses,
            checkAddresses:      checkAddresses,
            mintRecipients:      mintRecipients,
            layerZeroRecipients: layerZeroRecipients,
            maxSlippageParams:   maxSlippageParams,
            checkPsm:            checkPsm
        });
    }

    function setRateLimitData(
        bytes32 key,
        address rateLimits,
        uint256 maxAmount,
        uint256 slope,
        uint256 decimals
    )
        internal
    {
        // Handle setting an unlimited rate limit
        if (maxAmount == type(uint256).max) {
            require(slope == 0, "InvalidUnlimitedRateLimitSlope");
        } else {
            uint256 upperBound = 1e12 * (10 ** decimals);
            uint256 lowerBound = 10 ** decimals;

            require(maxAmount <= upperBound && maxAmount >= lowerBound,             "InvalidMaxAmountPrecision");
            require(slope <= upperBound / 1 hours && slope >= lowerBound / 1 hours, "InvalidSlopePrecision");
            require(slope != 0,                                                     "InvalidSlopePrecision");
        }

        IRateLimits(rateLimits).setRateLimitData(key, maxAmount, slope);
    }

    function configureVaultsV2(
        address vault_,
        uint256 supplyCap,
        uint256 minVsr,
        uint256 maxVsr,
        uint256 depositAmount,
        address ratelimits_,
        address controller_,
        address setter,
        address taker
    ) internal {
        ISparkVaultV2Like vault      = ISparkVaultV2Like(vault_);
        IRateLimits       rateLimits = IRateLimits(ratelimits_);
        MainnetController controller = MainnetController(controller_);

        // Grant SETTER_ROLE to ALM Proxy Freezable
        vault.grantRole(vault.SETTER_ROLE(), setter);

        // Grant TAKER_ROLE to Alm Proxy
        vault.grantRole(vault.TAKER_ROLE(), taker);

        // Set VSR bounds
        vault.setVsrBounds(minVsr, maxVsr);

        // Set the supply cap
        vault.setDepositCap(supplyCap);

        // Deposit into the vault
        SafeERC20.safeIncreaseAllowance(IERC20(vault.asset()), vault_, depositAmount);
        vault.deposit(depositAmount, address(1));

        rateLimits.setUnlimitedRateLimitData(
            RateLimitHelpers.makeAddressKey(
                controller.LIMIT_SPARK_VAULT_TAKE(),
                address(vault)
            )
        );

        rateLimits.setUnlimitedRateLimitData(
            RateLimitHelpers.makeAddressAddressKey(
                controller.LIMIT_ASSET_TRANSFER(),
                vault.asset(),
                address(vault)
            )
        );
    }

}
"
