    /*** Relayer Aave functions                                                                 ***/
    /**********************************************************************************************/

    function depositAave(address aToken, uint256 amount) external nonReentrant {
        _checkRole(RELAYER);

        AaveLib.deposit({
            proxy       : address(proxy),
            aToken      : aToken,
            amount      : amount,
            maxSlippage : maxSlippages[aToken],
